let translations = {};
let currentLang = localStorage.getItem('appLang') || 'en';


async function loadLanguage(lang) {
    try {
        const response = await fetch(`/static/i18n/${lang}.json`);
        if (!response.ok) {
            throw new Error(`Failed to load ${lang} translations`);
        }
        translations = await response.json();
        currentLang = lang;
        localStorage.setItem('appLang', lang);
        
        // Update DOM elements
        applyTranslations();
        
        // Update language selector dropdown if exists
        const langSelect = document.getElementById('lang-selector');
        if (langSelect) {
            langSelect.value = lang;
        }
        
    } catch (error) {
        console.error('i18n loading error:', error);
    }
}


function t(key, defaultText = '') {
    return translations[key] || defaultText || key;
}


function applyTranslations() {
    const elements = document.querySelectorAll('[data-i18n]');
    elements.forEach(el => {
        const key = el.getAttribute('data-i18n');
        
        // Handle input placeholders
        if (el.tagName === 'INPUT' && el.type !== 'button' && el.type !== 'submit') {
            const translated = t(key);
            if (translated !== key) {
                el.placeholder = translated;
            }
        } else {
            // Check if element has an icon child to preserve it
            const icon = el.querySelector('i');
            const translated = t(key);
            
            if (translated !== key) {
                if (icon) {
                    el.innerHTML = '';
                    el.appendChild(icon);
                    el.appendChild(document.createTextNode(' ' + translated));
                } else {
                    el.textContent = translated;
                }
            }
        }
    });
}


function initLanguageSelector() {
    const userMenu = document.querySelector('.user-menu');
    if (!userMenu) return;
    
    // Check if already injected
    if (document.getElementById('lang-selector')) return;
    
    const wrapper = document.createElement('div');
    wrapper.style.marginRight = '15px';
    wrapper.innerHTML = `
        <select id="lang-selector" class="form-control" style="width: 100px; padding: 4px 8px; height: 30px; font-size: 0.85rem;">
            <option value="en">English</option>
            <option value="kn">ಕನ್ನಡ</option>
            <option value="hi">हिंदी</option>
        </select>
    `;
    
    userMenu.insertBefore(wrapper, userMenu.firstChild);
    
    const select = document.getElementById('lang-selector');
    select.value = currentLang;
    
    select.addEventListener('change', (e) => {
        loadLanguage(e.target.value);
    });
}

// Automatically load default or saved language on page load
document.addEventListener('DOMContentLoaded', () => {
    initLanguageSelector();
    loadLanguage(currentLang);
});




const API_BASE_URL = '/api';
const TOKEN_KEY = 'agri_token';


function getToken() {
    return localStorage.getItem(TOKEN_KEY);
}


function setToken(token) {
    localStorage.setItem(TOKEN_KEY, token);
}


function removeToken() {
    localStorage.removeItem(TOKEN_KEY);
}


function isAuthenticated() {
    return !!getToken();
}


function requireAuth() {
    if (!isAuthenticated()) {
        ;
        return false;
    }
    return true;
}


async function apiRequest(endpoint, options = {}) {
    const url = `${API_BASE_URL}${endpoint}`;
    
    const headers = {
        'Content-Type': 'application/json',
        ...options.headers,
    };
    
    const token = getToken();
    if (token) {
        headers['Authorization'] = `Bearer ${token}`;
    }
    
    try {
        const response = await fetch(url, {
            ...options,
            headers,
        });
        
        const data = await response.json();
        
        // If unauthorized, redirect to login
        if (response.status === 401) {
            removeToken();
            const onAuthPage = window.location.pathname.includes('login') || window.location.pathname.includes('register') || window.locati;
            return null;
        }
        
        return data;
    } catch (error) {
        console.error('API request failed:', error);
        return {
            success: false,
            error: 'Network error. Please check your connection.',
            code: 0,
        };
    }
}


async function apiGet(endpoint) {
    return apiRequest(endpoint, { method: 'GET' });
}


async function apiPost(endpoint, body) {
    return apiRequest(endpoint, {
        method: 'POST',
        body: JSON.stringify(body),
    });
}


async function apiPut(endpoint, body) {
    return apiRequest(endpoint, {
        method: 'PUT',
        body: JSON.stringify(body),
    });
}


async function apiDelete(endpoint) {
    return apiRequest(endpoint, { method: 'DELETE' });
}


async function apiUpload(endpoint, formData) {
    const url = `${API_BASE_URL}${endpoint}`;
    const headers = {};
    
    const token = getToken();
    if (token) {
        headers['Authorization'] = `Bearer ${token}`;
    }
    
    try {
        const response = await fetch(url, {
            method: 'POST',
            headers,
            body: formData,
        });
        
        const data = await response.json();
        
        if (response.status === 401) {
            removeToken();
            const onAuthPage = window.location.pathname.includes('login') || window.location.pathname.includes('register') || window.locati;
            return null;
        }
        
        return data;
    } catch (error) {
        console.error('Upload failed:', error);
        return {
            success: false,
            error: 'Upload failed. Please try again.',
            code: 0,
        };
    }
}


function showToast(message, type = 'info', duration = 3000) {
    const existing = document.querySelector('.toast-notification');
    if (existing) existing.remove();
    
    const toast = document.createElement('div');
    toast.className = `toast-notification toast-${type}`;
    toast.innerHTML = `
        <i class="fas fa-${type === 'success' ? 'check-circle' : type === 'error' ? 'exclamation-circle' : 'info-circle'}"></i>
        <span>${message}</span>
    `;
    
    // Toast styles
    Object.assign(toast.style, {
        position: 'fixed',
        top: '20px',
        right: '20px',
        padding: '12px 20px',
        borderRadius: '8px',
        color: '#fff',
        fontSize: '14px',
        fontWeight: '500',
        display: 'flex',
        alignItems: 'center',
        gap: '8px',
        zIndex: '10000',
        animation: 'fadeInUp 0.3s ease-out',
        boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
        background: type === 'success' ? '#2E7D32' : type === 'error' ? '#C62828' : '#1565C0',
    });
    
    document.body.appendChild(toast);
    
    setTimeout(() => {
        toast.style.animation = 'fadeOutUp 0.3s ease-in forwards';
        setTimeout(() => toast.remove(), 300);
    }, duration);
}


async function downloadReport(predictionType, predictionId) {
    const token = getToken();
    if (!token) {
        if(window.showToast) window.showToast('Authentication required', 'error');
        return;
    }

    try {
        if(window.showToast) window.showToast('Generating PDF...', 'info');
        
        const response = await fetch(`${API_BASE_URL}/report/${predictionType}/${predictionId}`, {
            method: 'GET',
            headers: {
                'Authorization': `Bearer ${token}`
            }
        });

        if (!response.ok) {
            if(window.showToast) window.showToast('Could not generate report, please try again', 'error');
            return;
        }

        const blob = await response.blob();
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.style.display = 'none';
        a.href = url;
        a.download = `report_${predictionType}_${predictionId}.pdf`;
        document.body.appendChild(a);
        a.click();
        
        window.URL.revokeObjectURL(url);
        if(window.showToast) window.showToast('Report downloaded successfully!', 'success');
        
    } catch (err) {
        console.error('Download error:', err);
        if(window.showToast) window.showToast('Network error during download', 'error');
    }
}




